sys_script_include.script:
var ClaudeCapIncreaseHelper = Class.create();
ClaudeCapIncreaseHelper.prototype = {
    initialize: function() {},

    /**
     * findVPApprover(userSysId)
     *
     * Walks the manager chain of the given user upward, looking for the
     * first manager whose title contains 'VP' (case-insensitive).
     *
     * Algorithm:
     *   1. Get the manager of the requested-for user.
     *   2. If that manager's title contains 'VP' -> return their sys_id.
     *   3. If not, get the manager's manager and repeat.
     *   4. Stop after MAX_HOPS iterations to prevent infinite loops.
     *   5. If no VP is found, fall back to System Administrator.
     *
     * @param  {string} userSysId - sys_id of the requested-for user
     * @returns {string}          - sys_id of the VP approver (or fallback)
     */
    findVPApprover: function(userSysId) {
        var MAX_HOPS = 10;
        var currentUserId = userSysId;
        var visited = {};

        for (var hop = 0; hop < MAX_HOPS; hop++) {
            if (!currentUserId) { break; }
            if (visited[currentUserId]) {
                gs.warn('ClaudeCapIncreaseHelper.findVPApprover: circular manager chain detected at ' + currentUserId);
                break;
            }
            visited[currentUserId] = true;

            var userGR = new GlideRecord('sys_user');
            if (!userGR.get(currentUserId)) { break; }

            var managerId = userGR.getValue('manager');
            if (!managerId) {
                gs.warn('ClaudeCapIncreaseHelper.findVPApprover: no manager found for user ' + currentUserId + ' at hop ' + hop);
                break;
            }

            var managerGR = new GlideRecord('sys_user');
            if (!managerGR.get(managerId)) { break; }

            var managerTitle = (managerGR.getValue('title') || '').toUpperCase();
            gs.debug('ClaudeCapIncreaseHelper.findVPApprover: hop=' + hop +
                     ' manager=' + managerGR.getDisplayValue('name') +
                     ' title=' + managerTitle);

            if (managerTitle.indexOf('VP') !== -1) {
                gs.info('ClaudeCapIncreaseHelper.findVPApprover: Found VP at hop ' + hop +
                        ' -> ' + managerGR.getDisplayValue('name') +
                        ' (' + managerId + ')');
                return managerId;
            }

            currentUserId = managerId;
        }

        gs.warn('ClaudeCapIncreaseHelper.findVPApprover: No VP found in manager chain for user ' +
                userSysId + ' after ' + MAX_HOPS + ' hops. Falling back to System Administrator.');
        return this._getFallbackApprover();
    },

    /**
     * _getFallbackApprover()
     * Returns the sys_id of the System Administrator as a fallback approver.
     * @private
     * @returns {string} sys_id of System Administrator
     */
    _getFallbackApprover: function() {
        var gr = new GlideRecord('sys_user');
        gr.addQuery('user_name', 'admin');
        gr.setLimit(1);
        gr.query();
        if (gr.next()) { return gr.getUniqueValue(); }
        return '6816f79cc0a8016401c5a33be04be441';
    },

    /**
     * getTierLabel(requestType, tierValue)
     * Returns a human-readable label for display in work notes.
     * @param {string} requestType - 'claude' or 'claude_code'
     * @param {string} tierValue   - e.g. 'tier_1', 'a2'
     * @returns {string}
     */
    getTierLabel: function(requestType, tierValue) {
        var tierMap = {
            'claude': {
                'tier_1': 'Tier 1',
                'tier_2': 'Tier 2',
                'tier_3': 'Tier 3'
            },
            'claude_code': {
                'a1': 'A1',
                'a2': 'A2',
                'a3': 'A3'
            }
        };
        var appLabel = (requestType === 'claude_code') ? 'Claude Code' : 'Claude';
        var typeMap  = tierMap[requestType] || {};
        var tierLabel = typeMap[tierValue] || tierValue;
        return appLabel + ' - ' + tierLabel;
    },

    /**
     * updateRITMOnApproval(ritmSysId, approverSysId, comments, tier, requestType)
     *
     * Updates the RITM after VP approval:
     * - Sets work_notes with approval summary
     * - Sets comments (visible to requester)
     * - Sets approval = 'approved', state = 3 (Closed Complete)
     *
     * @param {string} ritmSysId    - sys_id of sc_req_item
     * @param {string} approverSysId - sys_id of the approving VP
     * @param {string} comments     - comments from the VP
     * @param {string} tier         - tier value selected (e.g. 'tier_1', 'a2')
     * @param {string} requestType  - 'claude' or 'claude_code'
     */
    updateRITMOnApproval: function(ritmSysId, approverSysId, comments, tier, requestType) {
        if (!ritmSysId) {
            gs.error('ClaudeCapIncreaseHelper.updateRITMOnApproval: ritmSysId is required.');
            return;
        }

        var ritm = new GlideRecord('sc_req_item');
        if (!ritm.get(ritmSysId)) {
            gs.error('ClaudeCapIncreaseHelper.updateRITMOnApproval: RITM not found - ' + ritmSysId);
            return;
        }

        var approverName = '';
        var approverTitle = '';
        if (approverSysId) {
            var approverGR = new GlideRecord('sys_user');
            if (approverGR.get(approverSysId)) {
                approverName  = approverGR.getDisplayValue('name');
                approverTitle = approverGR.getValue('title') || 'VP';
            }
        }

        var tierLabel = this.getTierLabel(requestType, tier);
        var now       = new GlideDateTime().getDisplayValue();

        ritm.work_notes =
            'APPROVED - Claude Cap Increase Request\n' +
            '--------------------------------------------\n' +
            'Application / Tier : ' + tierLabel + '\n' +
            'Max Cap Limit      : $300\n' +
            'Approved By        : ' + (approverName  || 'N/A') + '\n' +
            'Approver Title     : ' + (approverTitle || 'VP')  + '\n' +
            'Approval Date/Time : ' + now + '\n' +
            '--------------------------------------------\n' +
            'Approver Comments  : ' + (comments || 'No comments provided.');

        ritm.comments =
            'Your Claude Cap Increase Request for ' + tierLabel +
            ' has been approved by ' + (approverName || 'your VP') + '.\n\n' +
            'Comments: ' + (comments || 'None.');

        ritm.approval = 'approved';
        ritm.state    = 3;

        ritm.update();
        gs.info('ClaudeCapIncreaseHelper: RITM ' + ritmSysId + ' approved by VP ' + approverName);
    },

    /**
     * updateRITMOnRejection(ritmSysId, approverSysId, comments, tier, requestType)
     *
     * Updates the RITM after VP rejection:
     * - Sets work_notes with rejection summary
     * - Sets approval = 'rejected', state = 4 (Closed Incomplete)
     *
     * @param {string} ritmSysId    - sys_id of sc_req_item
     * @param {string} approverSysId - sys_id of the rejecting VP
     * @param {string} comments     - rejection comments from the VP
     * @param {string} tier         - tier value selected
     * @param {string} requestType  - 'claude' or 'claude_code'
     */
    updateRITMOnRejection: function(ritmSysId, approverSysId, comments, tier, requestType) {
        if (!ritmSysId) {
            gs.error('ClaudeCapIncreaseHelper.updateRITMOnRejection: ritmSysId is required.');
            return;
        }

        var ritm = new GlideRecord('sc_req_item');
        if (!ritm.get(ritmSysId)) {
            gs.error('ClaudeCapIncreaseHelper.updateRITMOnRejection: RITM not found - ' + ritmSysId);
            return;
        }

        var approverName  = '';
        var approverTitle = '';
        if (approverSysId) {
            var approverGR = new GlideRecord('sys_user');
            if (approverGR.get(approverSysId)) {
                approverName  = approverGR.getDisplayValue('name');
                approverTitle = approverGR.getValue('title') || 'VP';
            }
        }

        var tierLabel = this.getTierLabel(requestType, tier);
        var now       = new GlideDateTime().getDisplayValue();

        ritm.work_notes =
            'REJECTED - Claude Cap Increase Request\n' +
            '--------------------------------------------\n' +
            'Application / Tier : ' + tierLabel + '\n' +
            'Rejected By        : ' + (approverName  || 'N/A') + '\n' +
            'Rejector Title     : ' + (approverTitle || 'VP')  + '\n' +
            'Rejection Date/Time: ' + now + '\n' +
            '--------------------------------------------\n' +
            'Rejection Comments : ' + (comments || 'No comments provided.');

        ritm.comments =
            'Your Claude Cap Increase Request for ' + tierLabel +
            ' has been rejected by ' + (approverName || 'your VP') + '.\n\n' +
            'Reason: ' + (comments || 'None.');

        ritm.approval = 'rejected';
        ritm.state    = 4;

        ritm.update();
        gs.info('ClaudeCapIncreaseHelper: RITM ' + ritmSysId + ' rejected by VP ' + approverName);
    },

    type: 'ClaudeCapIncreaseHelper'
};

input.value:
(function execute(inputs, outputs) {
    var requestedForId = inputs.requested_for_sys_id;
    var helper = new ClaudeCapIncreaseHelper();
    outputs.vp_approver_sys_id = helper.findVPApprover(requestedForId);
})(inputs, outputs);

(function execute(inputs, outputs) {
    var helper       = new ClaudeCapIncreaseHelper();
    var ritmSysId    = inputs.ritm_sys_id;
    var approverSysId = inputs.approver_sys_id;
    var comments     = inputs.vp_comments;
    var requestType  = inputs.type_of_request;

    var tier = (requestType === 'claude_code')
               ? inputs.claude_code_tier
               : inputs.claude_tier;

    helper.updateRITMOnApproval(ritmSysId, approverSysId, comments, tier, requestType);
})(inputs, outputs);

(function execute(inputs, outputs) {
    var helper        = new ClaudeCapIncreaseHelper();
    var ritmSysId     = inputs.ritm_sys_id;
    var approverSysId = inputs.approver_sys_id;
    var comments      = inputs.vp_comments;
    var requestType   = inputs.type_of_request;

    var tier = (requestType === 'claude_code')
               ? inputs.claude_code_tier
               : inputs.claude_tier;

    helper.updateRITMOnRejection(ritmSysId, approverSysId, comments, tier, requestType);
})(inputs, outputs);
